const item = $input.first().json;
const fileData = item['Resume File'];
const fileName = fileData?.name || 'resume';
const isTex = fileName.toLowerCase().endsWith('.tex');
const formEmail = item['Your Email'] || '';
const thrRaw = item['ATS Threshold'];
let atsThreshold = parseInt(thrRaw, 10);
if (!Number.isFinite(atsThreshold) || atsThreshold < 0 || atsThreshold > 100) atsThreshold = 75;

return [{
  json: {
    jobTitle:     item['Target Job Title']    || '',
    company:      item['Target Company Name'] || '',
    jd:           item['Job Description']     || '',
    formEmail,
    fileName,
    fileType:     isTex ? 'text/x-tex' : (fileData?.mimeType || 'application/pdf'),
    isTex,
    timestamp:    new Date().toISOString(),
    runId:        Math.random().toString(36).substring(2, 10).toUpperCase(),
    atsThreshold
  },
  binary: $input.first().binary
}];

function toBase64(str) {
  const t = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
  const bytes = [];
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    if (c < 0x80) { bytes.push(c); }
    else if (c < 0x800) { bytes.push(0xC0|(c>>6), 0x80|(c&63)); }
    else { bytes.push(0xE0|(c>>12), 0x80|((c>>6)&63), 0x80|(c&63)); }
  }
  let r = '';
  for (let i = 0; i < bytes.length; i += 3) {
    const b0=bytes[i], b1=bytes[i+1]||0, b2=bytes[i+2]||0;
    r += t[b0>>2] + t[((b0&3)<<4)|(b1>>4)];
    r += i+1<bytes.length ? t[((b1&15)<<2)|(b2>>6)] : '=';
    r += i+2<bytes.length ? t[b2&63] : '=';
  }
  return r;
}
function fromBase64(str) {
  const t = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
  const s = str.replace(/[^A-Za-z0-9+/]/g,'');
  const bytes = [];
  for (let i = 0; i < s.length; i += 4) {
    const b0=t.indexOf(s[i]),b1=t.indexOf(s[i+1]),b2=s[i+2]==='='?0:t.indexOf(s[i+2]),b3=s[i+3]==='='?0:t.indexOf(s[i+3]);
    bytes.push((b0<<2)|(b1>>4));
    if (s[i+2]!=='=') bytes.push(((b1&15)<<4)|(b2>>2));
    if (s[i+3]!=='=') bytes.push(((b2&3)<<6)|b3);
  }
  let r='', i=0;
  while (i<bytes.length) {
    const b=bytes[i];
    if (b<0x80) { r+=String.fromCharCode(b); i++; }
    else if ((b&0xE0)===0xC0) { r+=String.fromCharCode(((b&31)<<6)|(bytes[i+1]&63)); i+=2; }
    else { r+=String.fromCharCode(((b&15)<<12)|((bytes[i+1]&63)<<6)|(bytes[i+2]&63)); i+=3; }
  }
  return r;
}
const binaryData = $input.first().binary || {};
const init       = $input.first().json;

const binaryKey = Object.keys(binaryData).find(k =>
  k.toLowerCase().includes('resume') ||
  k.toLowerCase().includes('file') ||
  k === 'data'
) || Object.keys(binaryData)[0];

if (!binaryKey || !binaryData[binaryKey]) {
  throw new Error('No file found. Keys: ' + JSON.stringify(Object.keys(binaryData)));
}

const file = binaryData[binaryKey];
let base64Data = file.data || '';
if (base64Data.includes(',')) base64Data = base64Data.split(',')[1];

if (!base64Data || base64Data.length < 10) {
  throw new Error('File data empty. Check N8N_DEFAULT_BINARY_DATA_MODE=default.');
}

// For .tex files: decode base64 → UTF-8 string directly
const resumeLatexSource = fromBase64(base64Data);

return [{
  json: {
    ...init,
    base64Data,
    mimeType: 'text/x-tex',
    resumeLatexSource
  }
}];

const resp = $input.first().json;
const init = $('Initialise + Store File').first().json;
const resumeLatexSource = $('Prepare File for Extraction').first().json.resumeLatexSource || '';

let extracted = {};
try {
  let raw = resp.choices?.[0]?.message?.content || '{}';
  raw = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();
  extracted = JSON.parse(raw);
} catch(e) {
  extracted = { personal:{}, current_role:{end_date:'Present'}, confidence:{}, missing_fields:[], full_resume_text:'' };
}

function stripLatex(src) {
  if (!src) return '';
  let t = src;
  t = t.replace(/\\documentclass[^\n]*\n?/g,'');
  t = t.replace(/\\usepackage(\[[^\]]*\])?\{[^}]*\}\s*/g,'');
  t = t.replace(/\\definecolor\{[^}]*\}\{[^}]*\}\{[^}]*\}\s*/g,'');
  t = t.replace(/\\hypersetup\{[^}]*\}\s*/g,'');
  t = t.replace(/\\titleformat\{[^}]*\}\{[^}]*\}\{[^}]*\}\{[^}]*\}\{[^}]*\}(\[[^\]]*\])?\s*/g,'');
  t = t.replace(/\\titlespacing\{[^}]*\}\{[^}]*\}\{[^}]*\}\{[^}]*\}\s*/g,'');
  t = t.replace(/\\setlength\{[^}]*\}\{[^}]*\}\s*/g,'');
  t = t.replace(/\\setlist\[[^\]]*\]\{[^}]*\}\s*/g,'');
  t = t.replace(/\\(begin|end)\{(document|center|itemize|multicols)\}(\{[^}]*\})?/g,'');
  t = t.replace(/\\pagestyle\{[^}]*\}/g,'');
  t = t.replace(/\\href\{[^}]*\}\{([^}]*)\}/g,'$1');
  t = t.replace(/\\section\*?\{([^}]*)\}/g,'\n== $1 ==\n');
  t = t.replace(/\\(?:textbf|textit|emph|LARGE|large|small|bfseries)\{([^}]*)\}/g,'$1');
  t = t.replace(/\\item\s*/g,'- ');
  t = t.replace(/\\\\/g,'\n');
  t = t.replace(/\\quad|\\cdot|\\\$/g,' ');
  t = t.replace(/\{|\}/g,'');
  t = t.replace(/\n{3,}/g,'\n\n');
  return t.trim();
}

const extractedText = extracted.full_resume_text || '';
const strippedFallback = stripLatex(resumeLatexSource);
const resumeText = (extractedText && extractedText.length >= 500) ? extractedText : strippedFallback;

const p    = extracted.personal      || {};
const cr   = extracted.current_role  || {};
const conf = extracted.confidence    || {};
const missing = extracted.missing_fields || [];

const lowConf = Object.entries(conf).filter(([,v]) => v === 'LOW' || v === 'MEDIUM').map(([k]) => k);
const warningFields = [...new Set([...missing, ...lowConf])];
const warningText = warningFields.length > 0
  ? 'Please check these fields — extracted with lower confidence: ' + warningFields.join(', ') + '.'
  : 'All fields extracted. Please review and confirm.';

return [{
  json: {
    ...init,
    extracted,
    resumeLatexSource,
    ex_name:       p.full_name    || '',
    ex_email:      p.email        || '',
    ex_phone:      p.phone        || '',
    ex_location:   p.location     || '',
    ex_linkedin:   p.linkedin     || '',
    ex_github:     p.github       || '',
    ex_cr_company: cr.company     || '',
    ex_cr_title:   cr.title       || '',
    ex_cr_start:   cr.start_date  || '',
    ex_cr_end:     cr.end_date    || 'Present',
    resumeText,
    confidence:    conf,
    missingFields: warningFields,
    warningFields,
    warningText
  }
}];

const prev = $('Parse Extracted Data').first().json;

function extractNameFromLatex(src) {
  if (!src) return '';
  const patterns = [
    /\\LARGE\s*\\bfseries\s+([A-Z][A-Za-z .\-']{1,60}[A-Za-z])/,
    /\\Huge\s*\\bfseries\s+([A-Z][A-Za-z .\-']{1,60}[A-Za-z])/,
    /\\LARGE\s+([A-Z][A-Za-z .\-']{1,60}[A-Za-z])/,
    /\\Huge\s+([A-Z][A-Za-z .\-']{1,60}[A-Za-z])/,
    /\{\s*\\(?:LARGE|Huge|huge)\s*\\bfseries\s+([A-Z][A-Za-z .\-']{1,60}[A-Za-z])\s*\}/,
    /\{\s*\\(?:LARGE|Huge|huge)\s+([A-Z][A-Za-z .\-']{1,60}[A-Za-z])\s*\}/,
    /\\bfseries\s+([A-Z][A-Za-z]+\s+[A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+)?)/,
    /\\name\s*\{([^}]+)\}/,
    /\\begin\{center\}[\s\S]{0,40}?([A-Z][a-z]+\s+[A-Z][a-z]+)[\s\S]{0,40}?\\\\/
  ];
  for (const re of patterns) {
    const m = src.match(re);
    if (m && m[1]) {
      const n = m[1].trim().replace(/\\\\$/,'').trim();
      if (n.length > 2 && /[A-Z]/.test(n)) return n;
    }
  }
  return '';
}
function nameFromEmail(email) {
  if (!email) return '';
  let local = email.split('@')[0];
  local = local.replace(/\d+/g,'').replace(/[._\-]+/g,' ').trim();
  if (!local) return '';
  return local.split(/\s+/).map(w => w ? w.charAt(0).toUpperCase() + w.slice(1) : '').filter(Boolean).join(' ');
}

let fullName = (prev.ex_name && prev.ex_name.trim().length > 2) ? prev.ex_name.trim() : '';
if (!fullName) fullName = extractNameFromLatex(prev.resumeLatexSource || '');
if (!fullName) fullName = nameFromEmail(prev.formEmail || prev.ex_email || '');
if (!fullName || fullName.length < 3) fullName = 'Candidate';

const email          = prev.formEmail || prev.ex_email || '';
const phone          = prev.ex_phone      || '';
const location       = prev.ex_location   || '';
const linkedin       = prev.ex_linkedin   || '';
const github         = prev.ex_github     || '';
const currentCompany = prev.ex_cr_company || '';
const currentTitle   = prev.ex_cr_title   || '';
const currentStart   = prev.ex_cr_start   || '';
const currentEnd     = prev.ex_cr_end     || 'Present';
const currentDateRange = currentStart + ' -- ' + currentEnd;

function escHdr(s) {
  if (!s) return '';
  return s.replace(/&/g,'\\&').replace(/%/g,'\\%').replace(/\$/g,'\\$').replace(/#/g,'\\#').replace(/_/g,'\\_').replace(/\^/g,'\\^{}').replace(/~/g,'\\textasciitilde{}');
}
function escUrlDisp(u) {
  if (!u) return '';
  return u.replace(/^https?:\/\//, '').replace(/_/g,'\\_').replace(/%/g,'\\%').replace(/#/g,'\\#').replace(/&/g,'\\&');
}
const headerParts = ['\\href{mailto:'+email+'}{'+escHdr(email)+'}'];
if (phone)    headerParts.push(escHdr(phone));
if (location) headerParts.push(escHdr(location));
if (linkedin) headerParts.push('\\href{https://'+linkedin.replace(/^https?:\/\//,'')+'}{'+escUrlDisp(linkedin)+'}');
if (github)   headerParts.push('\\href{https://'+github.replace(/^https?:\/\//,'')+'}{'+escUrlDisp(github)+'}');
const headerContact = headerParts.join(' \\quad $\\cdot$ \\quad ');
const safeName = fullName.replace(/&/g,'\\&').replace(/%/g,'\\%').replace(/#/g,'\\#');

let resumeWithDates = prev.resumeText || '';
if (prev.ex_cr_end && currentEnd !== prev.ex_cr_end) {
  resumeWithDates = resumeWithDates.replace(
    new RegExp(prev.ex_cr_end.replace(/[.*+?^${}()|[\]\\]/g,'\\$&'),'g'), currentEnd);
}
if (prev.ex_cr_title && currentTitle !== prev.ex_cr_title) {
  resumeWithDates = resumeWithDates.replace(
    new RegExp(prev.ex_cr_title.replace(/[.*+?^${}()|[\]\\]/g,'\\$&'),'g'), currentTitle);
}
if (prev.ex_cr_company && currentCompany !== prev.ex_cr_company) {
  resumeWithDates = resumeWithDates.replace(
    new RegExp(prev.ex_cr_company.replace(/[.*+?^${}()|[\]\\]/g,'\\$&'),'g'), currentCompany);
}

return [{
  json: {
    ...prev,
    fullName, email, phone, location, linkedin, github,
    currentCompany, currentTitle, currentStart, currentEnd,
    currentDateRange, headerContact, safeName,
    resumeWithDates,
    warningFields: prev.warningFields || []
  }
}];

const data = $input.first().json;
const jd = data.jd || '';
const src = data.resumeLatexSource || '';
function extract(name) { const re = new RegExp('\\section\*?\{\s*' + name + '\s*\}([\s\S]*?)(?=\\section\*?\{|\\end\{document\})', 'i'); const m = src.match(re); return m ? m[1].trim() : ''; }
const summarySrc = extract('Summary') || '';
const body = {
