const data = $input.first().json;
const resumeSrc = data.resumeLatexSource || data.resumeText || '';

const SYSTEM = `You are writing a cover letter from a candidate to a hiring team. Read as if you are the recruiter — is this candidate excited? Grounded? Did they study the JD?

STRUCTURE (exactly 4 paragraphs, 280-340 words, NO salutation, NO sign-off):

P1 — Hook: Why this specific company + specific role excites the candidate. Name the company. Name the role. Reference ONE concrete product/team/domain detail from the JD. Show genuine interest, not generic praise.

P2 — Proof: ONE concrete experience from RESUME that directly maps to JD responsibilities. Use the company + timeframe. Quantify ONLY what the RESUME already quantifies.

P3 — Alignment + growth: 3 specific tools or skills from RESUME that match JD. Then state ONE capability the candidate is actively learning or wants to develop in this role — frame as forward-looking ambition tied to the JD.

P4 — Close: Availability, eagerness to contribute, specific call to action (e.g., initial conversation). End with a confident future-oriented line.

TONE: Professional + warm. Show passion through SPECIFICS, not adjectives. Active voice. Recruiter should feel the candidate actually read the JD and is energized — not a templated apology.

HARD BANS:
- No placeholder text like [Company Name], [Previous Company], [Position].
- No generic phrases: "I am excited to", "passionate about", "leverage", "results-driven", "team player".
- No em-dashes.
- No salutation (Dear...), no sign-off (Sincerely...).
- No invented employers, tools, degrees, metrics.`;

const body = {
  model: "qwen2.5:3b",
  max_tokens: 1200,
  temperature: 0.75,
  stream: false,
  messages: [
    { role: "system", content: SYSTEM },
    { role: "user", content: `CANDIDATE NAME: ${data.fullName}\nCURRENT ROLE: ${data.currentTitle} at ${data.currentCompany}\nTARGET ROLE: ${data.jobTitle} at ${data.company}\n\nRESUME (source of truth — only draw from this):\n${resumeSrc}\n\n=== END RESUME ===\n\nJD (extract company details + 3-4 keywords):\n${data.jd}` }
  ]
};
return [{ json: { ...data, _groqBody: JSON.stringify(body) } }];

function getText(r) {
  try {
    if (r.choices)    return r.choices[0].message.content || '';
    if (r.candidates) return r.candidates[0].content.parts[0].text || '';
    return '';
  } catch(e) { return ''; }
}

function clean(t) { 
  return t.replace(/^```latex\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim(); 
}

function safeGet(nodeName) {
  try { 
    const raw = $(nodeName).first().json;
    const text = getText(raw);
    const cleaned = clean(text);
    // Return raw text if clean() removes too much
    return (cleaned && cleaned.length > 10) ? cleaned : text;
  } catch(e) { return ''; }
}

const base = $('Merge All Confirmed Data').first().json;

const candidates = {
  summary:    [ safeGet('Summary: llama-70b'),    safeGet('Summary: gemini-2.0-flash')    ],
  experience: [ safeGet('Experience: llama-70b'), safeGet('Experience: gemini-2.0-flash') ],
  skills:     [ safeGet('Skills: llama-70b'),     safeGet('Skills: gemini-2.0-flash')     ],
  projects:   [ safeGet('Projects: llama-70b'),   safeGet('Projects: gemini-2.0-flash')   ],
};

// Soft validation — use first non-empty candidate, never throw
for (const [section, cands] of Object.entries(candidates)) {
  const valid = cands.filter(c => c && c.trim().length > 10);
  if (valid.length === 0) {
    // Use whatever we got, even if short
    const any = cands.find(c => c && c.trim().length > 0);
    if (any) {
      candidates[section] = [any, any];
    }
    // If truly empty, let Judge handle it
  }
}

return [{ json: { ...base, candidates } }];

