  if (!s) return '';
  return s
    .replace(/ä/g,'a').replace(/Ä/g,'A')
    .replace(/ö/g,'o').replace(/Ö/g,'O')
    .replace(/ü/g,'u').replace(/Ü/g,'U')
    .replace(/ß/g,'ss')
    .normalize('NFD').replace(/[\u0300-\u036f]/g,'');
}

function tokens(text) {
  return fold(text || '').toLowerCase()
    .replace(/[^a-z0-9+\-.#/ ]/g,' ')
    .split(/\s+/)
    .filter(w => w.length > 1 && !STOP.has(w));
}

const jdFolded = fold(jdRaw).toLowerCase();
const jdToks = tokens(jdRaw);

// Known tech lexicon — single terms that count as keywords when present.
const TECH_LEX = [
  'python','java','javascript','typescript','c++','c#','matlab','fortran','r','go','rust','scala','ruby','php','swift','kotlin',
  'pytorch','tensorflow','keras','numpy','pandas','scikit-learn','sklearn','scipy','jax','hugging-face','transformers','langchain',
  'react','angular','vue','node','nodejs','express','django','flask','fastapi','spring','laravel','rails',
  'sql','mysql','postgres','postgresql','mongodb','redis','cassandra','elasticsearch','kafka','rabbitmq',
  'docker','kubernetes','k8s','terraform','ansible','jenkins','gitlab','github','git','ci/cd',
  'aws','azure','gcp','cloud','linux','unix','bash','shell','windows',
  'machine-learning','deep-learning','neural','nlp','cv','vision','llm','gpt','bert','cnn','rnn','lstm','transformer','rag',
  'ai','ml','ki','dl','data','analytics','statistics','mathematics','physics','engineering','algorithm','optimization','optimisation',
  'fem','cae','cfd','finite-elemente','finite-element','simulation','simulationsdaten','cad','ansys','abaqus','catia','solidworks','nastran','lsdyna','openfoam','comsol',
  'automotive','embedded','iot','rest','api','graphql','microservice','microservices','distributed','parallel','gpu','cuda',
  'scrum','agile','kanban','jira','confluence',
  'mlops','devops','mle','sre'
];
const TECH_SET = new Set(TECH_LEX.map(fold));

// Collect keywords from JD: tech-lex hits first, then hyphenated/compound, then salient phrases.
const jdWords = new Set(jdToks);
const keywords = [];
const pushed = new Set();

function push(term, priority) {
  const k = term.trim();
  if (!k || pushed.has(k)) return;
  pushed.add(k);
  keywords.push({ term: k, priority });
}

// 1) Tech lexicon hits.
for (const t of TECH_LEX) {
  const folded = fold(t);
  if (jdFolded.includes(folded)) push(folded, 'HIGH');
}

// 2) Hyphenated compounds in JD (typical tech terms).
const hyphRe = /[a-z0-9]+(?:-[a-z0-9]+){1,3}/g;
let m;
while ((m = hyphRe.exec(jdFolded)) !== null) {
  if (m[0].length >= 5 && !STOP.has(m[0])) push(m[0], 'MEDIUM');
}

// 3) Capitalized acronyms (3-5 uppercase letters) from raw JD.
const acroRe = /\b[A-Z]{2,6}\b/g;
while ((m = acroRe.exec(jdRaw)) !== null) {
  const a = fold(m[0]).toLowerCase();
  if (a.length >= 2 && !STOP.has(a)) push(a, 'MEDIUM');
}

// 4) Frequent meaningful single words (length >= 5, not stop, freq >= 2).
const freq = new Map();
for (const t of jdToks) {
  if (t.length >= 5 && !STOP.has(t)) freq.set(t, (freq.get(t) || 0) + 1);
}
for (const [t, c] of freq.entries()) {
  if (c >= 2) push(t, 'LOW');
}

// Cap to top 25, sorted HIGH > MEDIUM > LOW.
const PRI = { HIGH: 3, MEDIUM: 2, LOW: 1 };
keywords.sort((a, b) => PRI[b.priority] - PRI[a.priority]);
const keywordSet = keywords.slice(0, 25);

// Build resume corpus (folded).
const resumeAll = fold([sections.summary, sections.experience, sections.skills, sections.projects].filter(Boolean).join(' ')).toLowerCase();

const matched = [];
const missing = [];
for (const kw of keywordSet) {
  // Treat hyphen and space as interchangeable.
  const needles = [kw.term, kw.term.replace(/-/g,' '), kw.term.replace(/-/g,'')];
  const present = needles.some(n => n && resumeAll.includes(n));
  if (present) matched.push(kw.term);
  else missing.push({
    keyword: kw.term,
    importance: kw.priority,
    suggested_insertion: kw.priority === 'HIGH' ? 'Skills and Experience' : 'Skills section'
  });
}

const keyword_match_percent = keywordSet.length > 0
  ? Math.round((matched.length / keywordSet.length) * 100)
  : 0;

function sectionScore(name, text) {
  if (!text) return { score: 0, feedback: 'Section empty.' };
  const lc = fold(text).toLowerCase();
  const hits = keywordSet.filter(k => {
    const needles = [k.term, k.term.replace(/-/g,' '), k.term.replace(/-/g,'')];
    return needles.some(n => n && lc.includes(n));
  }).length;
  const score = keywordSet.length ? Math.round((hits / keywordSet.length) * 100) : 50;
  const wc = text.split(/\s+/).length;
  let fb = `${hits}/${keywordSet.length} JD keywords present; ${wc} words.`;
  if (score < 30) fb += ' Weak — add more JD-aligned terms.';
  else if (score < 60) fb += ' Moderate coverage.';
  else fb += ' Strong coverage.';
  return { score, feedback: fb };
}

