function pickBullets(src, n) {
  if (!src) return [];
  const items = [];
  const re = /\\item\s+([^\n\\]+(?:\\[^a-z\n][^\n]*)*)/g;
  let m;
  while ((m = re.exec(src)) !== null && items.length < n) {
    let txt = m[1].trim()
      .replace(/\\textbf\{([^}]*)\}/g,'$1')
      .replace(/\\textit\{([^}]*)\}/g,'$1')
      .replace(/\\href\{[^}]*\}\{([^}]*)\}/g,'$1')
      .replace(/\\[a-z]+(\{[^}]*\})?/g,'')
      .replace(/\s+/g,' ').trim();
    if (txt.length > 20) items.push(txt.replace(/\.+\s*$/, ''));
  }
  return items;
}

function pickSkills(src, jd) {
  if (!src) return [];
  const skills = [];
  const re = /\\item\s+([^\n]+)/g;
  let m;
  while ((m = re.exec(src)) !== null) {
    const line = m[1].replace(/\\[a-z]+(\{[^}]*\})?/g,'').replace(/[{}]/g,'').trim();
    line.split(/[,;]/).forEach(s => { const t = s.trim(); if (t.length > 1 && t.length < 40) skills.push(t); });
  }
  const jdLc = (jd || '').toLowerCase();
  const scored = skills.map(s => ({ s, hit: jdLc.includes(s.toLowerCase().split(' ')[0]) ? 1 : 0 }));
  scored.sort((a,b) => b.hit - a.hit);
  return [...new Set(scored.map(x => x.s))].slice(0, 6);
}

function pickJdKeywords(jd) {
  if (!jd) return [];
  const STOP = new Set(['This','That','The','Your','You','Our','Their','These','Those','With','Have','Will','Would','Should','Could','Were','When','What','Where','Which','About','Into','Over','Under','From','Team','Role','Work','Job','Position','Skills','Requirements','Responsibilities','Research','Development','Company','Office','Candidate','Candidates','Benefits','Experience','Qualifications','Preferred','Required','Duties','German','English','French','Spanish','Good','Great','Strong','Deep']);
  const caps = [...new Set((jd.match(/\b[A-Z][A-Za-z]{2,}\b/g) || []))].filter(w => !STOP.has(w));
  const scored = caps.map(w => {
    let score = 0;
    if (/^[A-Z]{2,}$/.test(w)) score += 3;
    if (/[A-Z].*[a-z].*[A-Z]/.test(w)) score += 2;
    if (/Python|Java|SQL|Docker|Kubernetes|Linux|AWS|Azure|GCP|AI|ML|LLM|NLP|API|REST|React|Vue|Angular|PyTorch|TensorFlow|CAE|FEM|CAD|CFD|CAN|LIN|ECU|Ethernet|CI|CD/i.test(w)) score += 5;
    if (w.length > 4) score += 1;
    return { w, score };
  });
  scored.sort((a,b) => b.score - a.score);
  return scored.map(x => x.w).slice(0, 6);
}

function buildTemplate() {
  const src = base.resumeLatexSource || '';
  const expSrc = (src.match(/\\section\*?\{\s*(?:Professional\s+)?Experience\s*\}([\s\S]*?)(?=\\section|\\end\{document\})/i) || ['',''])[1];
  const projSrc = (src.match(/\\section\*?\{\s*Projects\s*\}([\s\S]*?)(?=\\section|\\end\{document\})/i) || ['',''])[1];
  const skillsSrc = (src.match(/\\section\*?\{\s*Skills\s*\}([\s\S]*?)(?=\\section|\\end\{document\})/i) || ['',''])[1];

  const expBullets = pickBullets(expSrc, 3);
  const projBullets = pickBullets(projSrc, 2);
  const skills = pickSkills(skillsSrc, base.jd || '');
  const jdKws = pickJdKeywords(base.jd || '');
  const currentRole = base.currentTitle || 'my current role';
  const currentCompany = base.currentCompany || '';
  const atCompany = currentCompany ? ` at ${currentCompany}` : '';

  const domainHint = jdKws.slice(0, 2).join(' and ') || 'the domain you work in';

  const p1 = `The ${jobTitle} role at ${companyName} caught my attention because it sits exactly at the intersection of ${domainHint} and the kind of engineering work I want to do next. Reading the JD, I see a team building ${jdKws[0] ? jdKws[0].toLowerCase() : 'ambitious'} systems where careful engineering matters — that maps directly to what I have been doing, and to where I want to grow.`;

  const p2Core = expBullets[0] ? expBullets[0].replace(/^[A-Z]/, c => c.toLowerCase()) : 'built production tooling and debugged complex systems end to end';
  const p2Extra = expBullets[1] ? ` Alongside that work, I ${expBullets[1].replace(/^[A-Z]/, c => c.toLowerCase())}.` : '';
  const p2 = `In ${currentRole}${atCompany}, I ${p2Core}.${p2Extra} That experience taught me how to move from ambiguous requirements to working systems, which is the pattern I see described across the ${jobTitle} responsibilities.`;

  const skillsLine = skills.slice(0, 4).join(', ');
  const p3Core = skillsLine ? `On the tooling side I work comfortably with ${skillsLine}, which overlaps directly with the stack described in the JD.` : 'My technical foundation overlaps directly with the stack described in the JD.';
  const projLine = projBullets[0] ? ` A recent project: ${projBullets[0]}.${projBullets[1] ? ' Earlier, ' + projBullets[1].replace(/^[A-Z]/, c => c.toLowerCase()) + '.' : ''}` : '';
  const growthTarget = jdKws.filter(k => !/This|That|The/.test(k))[0] || (jobTitle || 'this area');
  const p3 = `${p3Core}${projLine} I want to go deeper on ${growthTarget} in applied settings, and ${companyName} is exactly the environment where that growth happens under experienced mentors.`;

  const p4 = `I am available to start on your timeline and would welcome a short conversation about where I can contribute first. The ${jobTitle} role is the role I want to grow into, and I would bring full commitment to the work ${companyName} is doing.`;

  return [p1, p2, p3, p4].join('\n\n');
}

