function escLatex(s) {
  if (!s) return '';
  return s
    .replace(/\\/g,'\\textbackslash{}')
    .replace(/([&%$#_{}])/g,'\\$1')
    .replace(/~/g,'\\textasciitilde{}')
    .replace(/\^/g,'\\textasciicircum{}')
    .replace(/\u2014/g,'---').replace(/\u2013/g,'--')
    .replace(/[\u2018\u2019]/g,"'").replace(/[\u201C\u201D]/g,'"');
}

